120→/// Broadcasts channel events over the gateway WebSocket.
121→///
122→/// Uses a deferred `OnceCell` reference so the sink can be created before
123→/// `GatewayState` exists (same pattern as cron callbacks).
124→pub struct GatewayChannelEventSink {
125→    state: Arc<tokio::sync::OnceCell<Arc<GatewayState>>>,
126→    #[cfg(feature = "crm")]
127→    crm_store: Option<Arc<dyn moltis_crm::CrmStore>>,
128→    #[cfg(feature = "crm")]
129→    crm_config: moltis_config::schema::CrmConfig,
130→}
131→
132→impl GatewayChannelEventSink {
133→    pub fn new(state: Arc<tokio::sync::OnceCell<Arc<GatewayState>>>) -> Self {
134→        Self {
135→            state,
136→            #[cfg(feature = "crm")]
137→            crm_store: None,
138→            #[cfg(feature = "crm")]
139→            crm_config: moltis_config::schema::CrmConfig::default(),
140→        }
141→    }
142→
143→    #[cfg(feature = "crm")]
144→    #[must_use]
145→    pub fn with_crm(
146→        mut self,
147→        store: Arc<dyn moltis_crm::CrmStore>,
148→        config: moltis_config::schema::CrmConfig,
149→    ) -> Self {
150→        self.crm_store = Some(store);
151→        self.crm_config = config;
152→        self
153→    }
154→}
155→
156→/// Handle CRM side-effects for an inbound channel message.
157→///
158→/// Runs fire-and-forget inside a `tokio::spawn`. Never blocks message delivery.
159→#[cfg(feature = "crm")]
160→async fn handle_crm_inbound(
161→    store: Arc<dyn moltis_crm::CrmStore>,
162→    config: moltis_config::schema::CrmConfig,
163→    channel_type: String,
164→    peer_id: String,
165→    username: Option<String>,
166→    sender_name: Option<String>,
167→) {
168→    use moltis_crm::{Contact, ContactChannel, Interaction, InteractionKind};
169→
170→    if peer_id.is_empty() {
171→        return;
172→    }
173→
174→    // 1. Look up existing channel link.
175→    let existing_channel = match store.get_channel_by_external(&channel_type, &peer_id).await {
176→        Ok(ch) => ch,
177→        Err(e) => {
178→            warn!(error = %e, channel_type, peer_id, "CRM inbound handling failed: channel lookup");
179→            return;
180→        },
181→    };
182→
183→    // Resolve contact name: sender_name > username > peer_id.
184→    let resolved_name = sender_name
185→        .as_deref()
186→        .filter(|s| !s.is_empty())
187→        .or_else(|| username.as_deref().filter(|s| !s.is_empty()))
188→        .unwrap_or(&peer_id)
189→        .to_string();
190→
191→    let contact_id = if let Some(ch) = existing_channel {
192→        let contact_id = ch.contact_id.clone();
193→
194→        // Update name if sender_name changed.
195→        if let Some(ref name) = sender_name
196→            && !name.is_empty()
197→        {
198→            match store.get(&contact_id).await {
199→                Ok(Some(mut contact)) if contact.name != *name => {
200→                    contact.name = name.clone();
201→                    if let Err(e) = store.upsert(contact).await {
202→                        warn!(error = %e, contact_id, "CRM: failed to update contact name");
203→                    }
204→                },
205→                Ok(_) => {},
206→                Err(e) => {
207→                    warn!(error = %e, contact_id, "CRM: failed to fetch contact for name update");
208→                },
209→            }
210→        }
211→
212→        contact_id
213→    } else {
214→        // No existing channel link found.
215→        if !config.auto_create_contacts {
216→            return;
217→        }
218→
219→        // Create contact + channel link.
220→        let contact = Contact::with_source(&resolved_name, &channel_type, &peer_id);
221→        let contact_id = contact.id.clone();
222→
223→        if let Err(e) = store.upsert(contact).await {
224→            warn!(error = %e, channel_type, peer_id, "CRM: failed to create contact");
225→            return;
226→        }
227→
228→        let channel_link = ContactChannel::new(&contact_id, &channel_type, &peer_id);
229→        if let Err(e) = store.upsert_channel(channel_link).await {
230→            warn!(error = %e, channel_type, peer_id, "CRM: failed to link contact channel");
231→            return;
232→        }
233→
234→        debug!(
235→            contact_id,
236→            channel_type, peer_id, "auto-created CRM contact"
237→        );
238→        contact_id
239→    };
240→
241→    // 3. Log the interaction.
